    12→
    13→import axios from 'axios';
    14→import EventEmitter from 'eventemitter3';
    15→import { getAccessToken, logout } from './authService'; // ← centralised auth utils
    16→import { API_BASE_URL, API_TIMEOUT } from '../config/env';
    17→import { createTTLCache } from '../utils/cache';
    18→
    19→/* -------------------------------------------------------------------------- */
    20→/*                                axios client                                */
    21→/* -------------------------------------------------------------------------- */
    22→
    23→/**
    24→ * Axios instance pre-configured with:
    25→ *  – Base URL from env config
    26→ *  – JWT bearer token injector
    27→ *  – Global error interceptors
