    29→const http = axios.create({
    30→  baseURL: `${API_BASE_URL}/courses`,
    31→  timeout: API_TIMEOUT,
    32→});
    33→
    34→// Request interceptor: inject auth token transparently
    35→http.interceptors.request.use(
    36→  async (config) => {
    37→    const token = await getAccessToken();
    38→    if (token) {
    39→      // eslint-disable-next-line no-param-reassign
    40→      config.headers.Authorization = `Bearer ${token}`;
    41→    }
    42→    return config;
    43→  },
    44→  (err) => Promise.reject(err),
    45→);
    46→
    47→// Response interceptor: unified error parsing & global side-effects
    48→http.interceptors.response.use(
    49→  (res) => res,
    50→  (error) => {
