    19→'use strict';
    20→
    21→/* ───────────────────────────────── External Dependencies ─────────────────── */
    22→const { PrismaClient, Prisma } = require('@prisma/client');
    23→const { Kafka }           = require('kafkajs');
    24→const Redis               = require('ioredis');
    25→const { v4: uuid }        = require('uuid');
    26→const winston             = require('winston');
    27→const _                   = require('lodash');
    28→
    29→/* ───────────────────────────────── Internal Dependencies ─────────────────── */
    30→const { EventTopics }     = require('../constants/event-topics');
    31→const { AppError }        = require('../errors/app-error');
    32→const { ErrorCodes }      = require('../constants/error-codes');
    33→
    34→/* ───────────────────────────────── Singleton Instances ───────────────────── */
    35→const prisma  = new PrismaClient();
    36→const redis   = new Redis(process.env.REDIS_URL || 'redis://localhost:6379');
    37→
    38→const kafka   = new Kafka({
    39→  clientId: 'course-service',
    40→  brokers : (process.env.KAFKA_BROKERS || 'localhost:9092').split(',')
    41→});
    42→const producer = kafka.producer();
    43→
    44→/* ───────────────────────────────── Logger Setup ──────────────────────────── */
    45→const logger = winston.createLogger({
    46→  level    : process.env.NODE_ENV === 'production' ? 'info' : 'debug',
    47→  transports: [
    48→    new winston.transports.Console({
    49→      format: winston.format.combine(
    50→        winston.format.colorize(),
    51→        winston.format.timestamp(),
    52→        winston.format.printf(
    53→          ({ timestamp, level, message, ...meta }) =>
    54→            `${timestamp} [${level}] ${message} ${Object.keys(meta).length ? JSON.stringify(meta) : ''}`
    55→        )
    56→      )
    57→    })
    58→  ]
    59→});
    60→
    61→/* ───────────────────────────────── Utility Functions ─────────────────────── */
    62→
    63→/**
    64→ * Centralized helper to publish events to Kafka.
    65→ * All events from this service should pass through this function to guarantee
    66→ * consistent headers, tracing IDs, and error handling.
    67→ *
    68→ * @param {String} topic
    69→ * @param {Object} payload
    70→ * @param {Object} [headers={}] - Additional Kafka headers
    71→ */
    72→async function publishEvent(topic, payload, headers = {}) {
    73→  try {
    74→    await producer.connect(); // NOOP after first call
    75→    await producer.send({
    76→      topic,
    77→      messages: [
    78→        {
    79→          key    : uuid(),           // partitioning key
    80→          value  : JSON.stringify(payload),
    81→          headers: {
    82→            'trace-id': uuid(),
    83→            ...headers
    84→          }
    85→        }
    86→      ]
    87→    });
    88→    logger.debug(`Event published: ${topic}`, { payload });
    89→  } catch (err) {
    90→    // We never throw from publishEvent; instead we log and continue.
    91→    logger.error('Failed to publish event', { topic, err: err.stack || err });
    92→  }
    93→}
    94→
    95→/**
    96→ * Cache wrapper for GET queries. Uses Redis with JSON serialization.
    97→ * @param {String} key
    98→ * @param {Function} resolver - Function that returns a Promise of the data
    99→ * @param {Number} ttlSeconds - Time-to-live
   100→ */
   101→async function getOrSetCache(key, resolver, ttlSeconds = 60) {
   102→  const cached = await redis.get(key);
   103→  if (cached) {
   104→    return JSON.parse(cached);
   105→  }
   106→  const fresh = await resolver();
   107→  await redis.set(key, JSON.stringify(fresh), 'EX', ttlSeconds);
   108→  return fresh;
   109→}
