   111→/* ───────────────────────────────── Domain Service ────────────────────────── */
   112→class CourseService {
   113→  /* ======================================================================= *
   114→   * PUBLIC API                                                              *
   115→   * ======================================================================= */
   116→
   117→  /**
   118→   * Creates a brand-new course and its initial metadata.
   119→   * @param {Object} courseData
   120→   * @param {String} creatorId
   121→   * @returns {Promise<Object>} Newly created course
   122→   */
   123→  async createCourse(courseData, creatorId) {
   124→    const { title, description, category, thumbnailUrl, publishedAt } = courseData;
   125→
   126→    // Basic validation
   127→    if (!title || title.length < 3) {
   128→      throw new AppError('Course title must be at least 3 characters long', ErrorCodes.VALIDATION);
   129→    }
   130→
   131→    try {
   132→      const course = await prisma.$transaction(async (tx) => {
   133→        // 1. Insert into Course table
   134→        const newCourse = await tx.course.create({
   135→          data: {
   136→            id          : uuid(),
   137→            title,
   138→            description,
   139→            category,
   140→            thumbnailUrl,
   141→            publishedAt : publishedAt || null,
   142→            creatorId,
   143→            status      : 'DRAFT'
   144→          }
   145→        });
   146→
   147→        // 2. Auto-enroll creator as instructor
   148→        await tx.courseEnrollment.create({
   149→          data: {
   150→            userId  : creatorId,
   151→            courseId: newCourse.id,
   152→            role    : 'INSTRUCTOR'
   153→          }
   154→        });
   155→
   156→        return newCourse;
   157→      });
   158→
   159→      // 3. Publish event outside transaction
   160→      await publishEvent(EventTopics.COURSE_CREATED, {
   161→        courseId : course.id,
   162→        creatorId,
   163→        timestamp: new Date().toISOString()
   164→      });
   165→
   166→      return course;
   167→    } catch (err) {
   168→      logger.error('createCourse failed', { err: err.stack || err });
   169→      if (err instanceof Prisma.PrismaClientKnownRequestError && err.code === 'P2002') {
   170→        // Unique constraint.
   171→        throw new AppError('A course with the same title already exists', ErrorCodes.CONFLICT);
   172→      }
   173→      throw err;
   174→    }
   175→  }
   176→
   177→  /**
   178→   * Retrieves a course by its ID, with optional lessons & enrollment info.
   179→   * Makes heavy use of Redis for fast repeated look-ups.
   180→   *
   181→   * @param {String} courseId
   182→   * @param {Object} [options]
   183→   * @param {Boolean} [options.includeLessons=false]
   184→   * @param {Boolean} [options.includeStats=false]
   185→   */
   186→  async getCourseById(courseId, options = {}) {
   187→    if (!courseId) throw new AppError('courseId is required', ErrorCodes.VALIDATION);
   188→    const { includeLessons = false, includeStats = false } = options;
   189→
   190→    const cacheKey = `course:${courseId}:${includeLessons}:${includeStats}`;
   191→
   192→    return getOrSetCache(
   193→      cacheKey,
   194→      async () => {
   195→        const course = await prisma.course.findUnique({
   196→          where: { id: courseId },
   197→          include: {
   198→            lessons: includeLessons,
   199→            // stats is a materialized view; simulated via compute
   200→          }
   201→        });
   202→
   203→        if (!course) {
   204→          throw new AppError('Course not found', ErrorCodes.NOT_FOUND);
   205→        }
   206→
   207→        if (includeStats) {
   208→          const [enrolled, completed] = await Promise.all([
   209→            prisma.courseEnrollment.count({ where: { courseId } }),
   210→            prisma.lessonCompletion.count({ where: { courseId } })
   211→          ]);
   212→          course.stats = { enrolled, completed };
   213→        }
   214→
   215→        return course;
   216→      },
   217→      30 // seconds
   218→    );
   219→  }
   220→
   221→  /**
   222→   * Updates mutable fields of a course.  Immutable fields like id and creatorId
   223→   * are ignored automatically via lodash.pick.
   224→   *
   225→   * @param {String} courseId
   226→   * @param {Object} updates
   227→   * @param {String} requesterId - Authorization performed here.
   228→   */
   229→  async updateCourse(courseId, updates, requesterId) {
   230→    const allowed = ['title', 'description', 'category', 'thumbnailUrl', 'publishedAt', 'status'];
   231→    const sanitized = _.pick(updates, allowed);
   232→
   233→    // Early bail-out
   234→    if (_.isEmpty(sanitized)) {
   235→      throw new AppError('No valid fields to update', ErrorCodes.VALIDATION);
   236→    }
   237→
   238→    // Authorization: only creator or admin can update
   239→    const course = await prisma.course.findUnique({ where: { id: courseId } });
   240→    if (!course) throw new AppError('Course not found', ErrorCodes.NOT_FOUND);
   241→
   242→    const isAdmin = await this.#isAdmin(requesterId);
   243→    if (course.creatorId !== requesterId && !isAdmin) {
   244→      throw new AppError('Forbidden', ErrorCodes.FORBIDDEN, 403);
   245→    }
   246→
   247→    try {
   248→      const updated = await prisma.course.update({
   249→        where: { id: courseId },
   250→        data : sanitized
   251→      });
   252→
   253→      // Invalidate cache
   254→      await redis.del(`course:${courseId}:*`);
   255→
   256→      await publishEvent(EventTopics.COURSE_UPDATED, {
   257→        courseId,
   258→        updaterId: requesterId,
   259→        changes  : Object.keys(sanitized),
   260→        timestamp: new Date().toISOString()
   261→      });
   262→
   263→      return updated;
   264→    } catch (err) {
   265→      logger.error('updateCourse failed', { err: err.stack || err });
   266→      throw err;
   267→    }
   268→  }
   269→
   270→  /**
   271→   * Enroll a user into a course, supports roles: STUDENT, AUDITOR
   272→   *
   273→   * @param {String} courseId
   274→   * @param {String} userId
   275→   * @param {"STUDENT"|"AUDITOR"} role
   276→   */
   277→  async enrollUser(courseId, userId, role = 'STUDENT') {
   278→    if (!['STUDENT', 'AUDITOR'].includes(role)) {
   279→      throw new AppError('Invalid role', ErrorCodes.VALIDATION);
   280→    }
   281→
   282→    try {
   283→      await prisma.courseEnrollment.create({
   284→        data: {
   285→          id      : uuid(),
   286→          courseId,
   287→          userId,
   288→          role
   289→        }
   290→      });
   291→
   292→      // Bump course enrollment count metric
   293→      await publishEvent(EventTopics.USER_ENROLLED, {
   294→        courseId,
   295→        userId,
   296→        role,
   297→        timestamp: new Date().toISOString()
   298→      });
   299→
   300→      // Evict course stats cache so count is fresh
   301→      await redis.del(`course:${courseId}:false:true`);
   302→    } catch (err) {
   303→      if (err instanceof Prisma.PrismaClientKnownRequestError && err.code === 'P2002') {
   304→        // Unique constraint violation → already enrolled
   305→        throw new AppError('User already enrolled', ErrorCodes.CONFLICT);
   306→      }
   307→      throw err;
   308→    }
   309→  }
   310→
   311→  /**
   312→   * Tracks lesson completion for a learner.
   313→   * @param {String} courseId
   314→   * @param {String} lessonId
   315→   * @param {String} userId
   316→   */
   317→  async completeLesson(courseId, lessonId, userId) {
   318→    const idempotencyKey = `${userId}:${lessonId}:completion`;
   319→    const lock = await redis.set(idempotencyKey, '1', 'NX', 'EX', 5);
   320→    if (!lock) {
   321→      // Duplicate submission within 5 seconds
   322→      return;
   323→    }
   324→
   325→    try {
   326→      await prisma.lessonCompletion.create({
   327→        data: {
   328→          id       : uuid(),
   329→          courseId,
   330→          lessonId,
   331→          userId
   332→        }
   333→      });
   334→
   335→      await publishEvent(EventTopics.LESSON_COMPLETED, {
   336→        courseId,
   337→        lessonId,
   338→        userId,
   339→        timestamp: new Date().toISOString()
   340→      });
   341→
   342→      await redis.del(`course:${courseId}:*`);
   343→    } catch (err) {
   344→      if (err instanceof Prisma.PrismaClientKnownRequestError && err.code === 'P2002') {
   345→        // Duplicate completion (idempotent)
   346→        return;
   347→      }
   348→      throw err;
   349→    }
   350→  }
   351→
   352→  /**
   353→   * Deletes a course; only admins can perform hard-deletes.
   354→   *
   355→   * @param {String} courseId
   356→   * @param {String} requesterId
   357→   */
   358→  async deleteCourse(courseId, requesterId) {
   359→    const isAdmin = await this.#isAdmin(requesterId);
   360→    if (!isAdmin) {
   361→      throw new AppError('Admin rights required', ErrorCodes.FORBIDDEN, 403);
   362→    }
   363→
   364→    await prisma.$transaction([
   365→      prisma.courseEnrollment.deleteMany({ where: { courseId } }),
   366→      prisma.lessonCompletion.deleteMany({ where: { courseId } }),
   367→      prisma.course.delete({ where: { id: courseId } })
   368→    ]);
   369→
   370→    await redis.del(`course:${courseId}:*`);
   371→
   372→    await publishEvent(EventTopics.COURSE_DELETED, {
   373→      courseId,
   374→      deleterId : requesterId,
   375→      timestamp : new Date().toISOString()
   376→    });
   377→
   378→    return { success: true };
   379→  }
   380→
   381→  /* ======================================================================= *
   382→   * PRIVATE HELPERS                                                         *
   383→   * ======================================================================= */
   384→
   385→  /**
   386→   * Determines if the user is an admin by checking cached claims.
   387→   * @private
   388→   * @param {String} userId
   389→   * @returns {Promise<Boolean>}
   390→   */
   391→  async #isAdmin(userId) {
   392→    const cacheKey = `user:${userId}:isAdmin`;
   393→    const cached   = await redis.get(cacheKey);
   394→    if (cached !== null) return cached === 'true';
   395→
   396→    // This would normally hit the Auth/User service. Hard-coded for brevity.
   397→    const isAdmin = await prisma.user.findUnique({
   398→      where : { id: userId },
   399→      select: { roles: true }
   400→    }).then(u => u?.roles.includes('ADMIN') || false);
   401→
   402→    await redis.set(cacheKey, isAdmin, 'EX', 60);
   403→    return isAdmin;
   404→  }
   405→}
   406→
   407→/* ───────────────────────── Exports (Singleton by Convention) ─────────────── */
   408→module.exports = new CourseService();
   409→```

