     2→/**
     3→ * PulseLearn Campus Hub – Course Service
     4→ * ---------------------------------------
     5→ * events/producer.js
     6→ *
     7→ * Event producer responsible for publishing domain events originating
     8→ * from the Course Service (e.g. CourseCreated, CourseUpdated) to the
     9→ * message bus. We rely on NATS Streaming (Stan) for at-least-once
    10→ * delivery semantics and use pino for structured logging.
    11→ *
    12→ * This module exposes a singleton instance that is:
    13→ *  – lazily connected (first call to `publish`)
    14→ *  – resilient (auto-reconnects with back-off and drains on shutdown)
    15→ *  – schema-aware (basic validation and version stamping)
    16→ *
    17→ * Environment variables:
    18→ *  NATS_CLUSTER_ID  – cluster identifier configured on the NATS server
    19→ *  NATS_CLIENT_ID   – unique client id for this producer
    20→ *  NATS_URL         – tunneling URL (e.g. nats://user:pass@localhost:4222)
    21→ */
    22→
    23→'use strict';
    24→
    25→const stan    = require('node-nats-streaming');
    26→const { v4: uuid } = require('uuid');
    27→const pino    = require('pino');
    28→
    29→// ---- Configuration ---------------------------------------------------------
    30→
    31→const {
    32→  NATS_CLUSTER_ID = 'pulselrn',
    33→  NATS_CLIENT_ID  = `course-svc-producer-${uuid().substring(0, 8)}`,
    34→  NATS_URL        = 'nats://localhost:4222',
    35→  NODE_ENV        = 'development'
    36→} = process.env;
    37→
    38→const LOGGER = pino({
    39→  level : NODE_ENV === 'production' ? 'info' : 'debug',
    40→  name  : 'course-service:event-producer'
    41→});
    42→
    43→// Publish-side subject naming convention
    44→const SUBJECTS = {
    45→  COURSE_CREATED : 'course.created',
    46→  COURSE_UPDATED : 'course.updated',
    47→  COURSE_ARCHIVED: 'course.archived'
    48→};
    49→
    50→// Maximum time in milliseconds the client will wait for an ACK from NATS
    51→const ACK_WAIT_MILLIS = 5_000;
    52→
    53→// ---- Internal Helpers ------------------------------------------------------
    54→
    55→/**
    56→ * Serialise payload and enrich with envelope metadata.
    57→ * @param {String} eventType
    58→ * @param {Object} data
    59→ */
    60→function buildMessage(eventType, data) {
    61→  return JSON.stringify({
    62→    id         : uuid(),       // event identifier for idempotency
    63→    version    : 1,            // domain event schema version
    64→    timestamp  : new Date().toISOString(),
    65→    emitter    : 'course-service',
    66→    event      : eventType,
    67→    payload    : data
    68→  });
    69→}
    70→
    71→/**
    72→ * Simple schema guard for course payloads.
    73→ * In production we could delegate to a proper JSON-schema validator
    74→ * such as Ajv; here we add a minimal safeguard so we do not publish
    75→ * garbage messages onto the bus.
    76→ */
    77→function validateCoursePayload(payload = {}) {
    78→  if (!payload.id || typeof payload.id !== 'string') {
    79→    throw new Error('Invalid payload: "id" is required and must be a string');
    80→  }
    81→  if (!payload.title || typeof payload.title !== 'string') {
    82→    throw new Error('Invalid payload: "title" is required and must be a string');
    83→  }
    84→}
    85→
    86→// ---- Producer Implementation ----------------------------------------------
    87→
    88→class EventProducer {
    89→
    90→  constructor() {
    91→    this._stan   = null;
    92→    this._ready  = false;
    93→    this._queue  = [];
    94→    this._drainInProgress = false;
    95→  }
    96→
    97→  /**
    98→   * Lazily create a connection to the NATS Streaming cluster.
    99→   * Connection is initialised only once per process.
   100→   * @returns {Promise<void>}
   101→   */
   102→  async _connect() {
   103→    if (this._stan || this._ready) return;
   104→    LOGGER.info({ cluster: NATS_CLUSTER_ID, client: NATS_CLIENT_ID, url: NATS_URL },
   105→                'Connecting to NATS Streaming…');
   106→
   107→    this._stan = stan.connect(NATS_CLUSTER_ID, NATS_CLIENT_ID, { url: NATS_URL });
   108→
   109→    // Promisify connection lifecycle
   110→    await new Promise((resolve, reject) => {
   111→      const onConnect = () => {
   112→        this._ready = true;
   113→        LOGGER.info('NATS Streaming connection established ✅');
   114→        this._flushQueue(); // emit messages that were queued before ready
   115→        resolve();
   116→      };
   117→
   118→      const onError = (err) => {
   119→        LOGGER.error({ err }, 'Unable to connect to NATS Streaming ❌');
   120→        reject(err);
   121→      };
   122→
   123→      this._stan.once('connect', onConnect);
   124→      this._stan.once('error',   onError);
   125→    });
   126→
   127→    // Attach common listeners AFTER the initial promise resolution
   128→    this._stan.on('close',  () => LOGGER.warn('NATS connection closed'));
   129→    this._stan.on('reconnect', () => LOGGER.info('NATS reconnected'));
   130→    this._stan.on('disconnect', () => LOGGER.warn('NATS disconnected'));
   131→  }
   132→
   133→  /**
   134→   * Drain NATS connection gracefully before process exit.
   135→   */
   136→  async close() {
   137→    if (!this._stan || this._drainInProgress) return;
   138→    this._drainInProgress = true;
   139→
   140→    LOGGER.info('Draining NATS Streaming connection before shutdown…');
   141→    await new Promise((resolve) => {
   142→      this._stan.drain(() => {
   143→        LOGGER.info('NATS drain complete, closing connection');
   144→        this._stan.close();
   145→        resolve();
   146→      });
   147→    });
   148→  }
   149→
   150→  /**
   151→   * Publish raw subject + message
   152→   * @param {String} subject
   153→   * @param {String} message   – already JSON serialised
   154→   * @param {Object} options   – optional metadata (e.g. persistentName)
   155→   * @returns {Promise<void>}
   156→   */
   157→  async _publish(subject, message, options = {}) {
   158→    await this._connect();
   159→
   160→    return new Promise((resolve, reject) => {
   161→      const guid = this._stan.publish(subject, message, (err, ackGuid) => {
   162→        if (err) {
   163→          LOGGER.error({ err, subject, guid }, 'Failed to publish message');
   164→          return reject(err);
   165→        }
   166→        LOGGER.debug({ subject, guid: ackGuid }, 'Event published');
   167→        resolve();
   168→      });
   169→
   170→      // Fallback: if no ack within ACK_WAIT_MILLIS, reject
   171→      setTimeout(() => {
   172→        reject(new Error(`ACK timeout after ${ACK_WAIT_MILLIS}ms for guid: ${guid}`));
   173→      }, ACK_WAIT_MILLIS).unref();
   174→    });
   175→  }
   176→
   177→  /**
   178→   * Queue messages if connection hasn't been established yet.
   179→   * This prevents any writes being lost during cold starts.
   180→   */
   181→  _queueMessage(subject, message) {
   182→    this._queue.push({ subject, message });
   183→  }
   184→
   185→  _flushQueue() {
   186→    if (!this._queue.length || !this._ready) return;
   187→
   188→    LOGGER.info(`Flushing ${this._queue.length} queued event(s)`);
   189→    this._queue.forEach(({ subject, message }) => {
   190→      this._stan.publish(subject, message, (err) => {
   191→        if (err) {
   192→          LOGGER.error({ subject, err }, 'Failed to publish queued event');
   193→        }
   194→      });
   195→    });
   196→    this._queue.length = 0;
   197→  }
   198→
   199→  // ---------------------------------------------------
   200→  // Domain-specific API
   201→  // ---------------------------------------------------
   202→
   203→  /**
   204→   * Course Created domain event publisher.
   205→   * @param {Object} course – plain JS object { id, title, … }
   206→   */
   207→  async courseCreated(course) {
   208→    try {
   209→      validateCoursePayload(course);
   210→      const msg = buildMessage('CourseCreated', course);
   211→      await this._publish(SUBJECTS.COURSE_CREATED, msg);
   212→    } catch (err) {
   213→      LOGGER.error({ err, course }, 'Unable to publish CourseCreated event');
   214→      throw err;
   215→    }
   216→  }
   217→
   218→  /**
   219→   * Course Updated domain event publisher.
   220→   * @param {Object} course – plain JS object { id, title, … }
   221→   */
   222→  async courseUpdated(course) {
   223→    try {
   224→      validateCoursePayload(course);
   225→      const msg = buildMessage('CourseUpdated', course);
   226→      await this._publish(SUBJECTS.COURSE_UPDATED, msg);
   227→    } catch (err) {
   228→      LOGGER.error({ err, course }, 'Unable to publish CourseUpdated event');
   229→      throw err;
   230→    }
   231→  }
   232→
   233→  /**
   234→   * Course archived event publisher.
   235→   * @param {Object} course – minimal object { id, archivedAt }
   236→   */
   237→  async courseArchived(course) {
   238→    if (!course.id) {
   239→      throw new Error('Invalid payload: "id" is required for archive event');
   240→    }
   241→
   242→    const msg = buildMessage('CourseArchived', course);
   243→    try {
   244→      await this._publish(SUBJECTS.COURSE_ARCHIVED, msg);
   245→    } catch (err) {
   246→      LOGGER.error({ err, course }, 'Unable to publish CourseArchived event');
   247→      throw err;
   248→    }
   249→  }
   250→}
   251→
   252→// ---- Singleton Export ------------------------------------------------------
   253→
   254→const producerInstance = new EventProducer();
   255→
   256→// Clean up before the Node process is terminated
   257→['SIGINT', 'SIGTERM', 'SIGQUIT'].forEach((signal) => {
   258→  process.on(signal, async () => {
   259→    LOGGER.info({ signal }, 'Received termination signal');
   260→    await producerInstance.close();
   261→    process.exit(0);
   262→  });
   263→});
   264→
   265→module.exports = producerInstance;
   266→```

